
import React, { useState, useEffect } from "react";

import "./styles.css"
import { CloseModal, OpenModal } from "../../../components/DialogHRM";
import {  SvgIcon_Cmpt, TextInput_Cmpt, SearchInput_Cmpt, LoadingColorSpinner_Cmpt } from "../../../components";
import { updStore, getStore, gen16CodeId, ObjectKeys, qryKClient } from "../../../stores/Utils";

import { search_notary, search_customer_logistic } from "../services/customer_fetch_service";
import ClientItem from "./customer_item";
import AddClientInfo from "./customer_detail_info_add";


const Svg = SvgIcon_Cmpt();


const SearchInput = SearchInput_Cmpt();

const LoadingColorSpinner = LoadingColorSpinner_Cmpt();







const CustomerView  = ({ title, description }) => {
	const [obs, set_obs] = useState(1);
	

	const [loading, set_loading] = useState(false);
	const [loadingData, set_loadingData] = useState(1);






	const updObs =  () => {
		set_obs(gen16CodeId())
	}

	const callbackSearch =  (td) => {
		setTimeout(() => {
			set_loading(false);
			set_loadingData(false);
			updStore("logistic_order_beneficiary", null);
			updStore("logistic_order_new", null);
			updStore("clientLogistic_list", td);
			updObs();
		}, 100);
		updObs();
	}

	const search_client = async (f, v) => {
		set_loading(true)
		search_customer_logistic(callbackSearch);
	};

	const handleChange =  (v) => {
		!loadingData && set_loadingData(true);
	}

	const closeDetails = () =>{

	}

	const addCustomer =  (v) => {
		let data = {};
		data["zIndex"] = 480;
		// data['observeResize']=true;
		data["props"] = { minHeight: "1vh", overlay: true };
		data["content"] = <AddClientInfo  confirm={closeDetails} />
		OpenModal(data);
	}
 


 
	return (
		<div className=" customer_bx_dash	 ">
			<div className="_dsplFlx " >
				<div className="iMTYiw" style={{marginTop: "8px"}}>
					Clientes
				</div>
				<div style={{marginTop: "8px"}}>
					<SearchInput
						loadingColor={"var(--primary)"}
						label={"Buscar un cliente"} 
						width={360}
						obs={set_obs}
						fetchData={search_client}
						//loading={loading}
						change={handleChange}
						callempty={search_client}
						keyFlds={"searchQryLogisticCustomer"}
					/>
				</div>
				<div className="flexSpace"/>
				<div className="iSTOvb kvXcCL"  style={{padding: "0 9px" , width: "160px"}}  onClick={addCustomer}>
					Agregar Cliente
				</div>
			</div>
			<div  style={{marginTop:32}}>
			{loadingData?
				<div  style={{marginTop:2}}>
				<div className="load_animation" style={{backgroundColor: "var(--primary-blue--backg-30)"}}/>
				<div className="_dsplFlx "  style={{marginTop:32}}>
					<div className="flexSpace"/>
					<div className="icon_compr _dsplFlx" >
						<div className="lbl_saving">
								searching ... 
						</div>
						<LoadingColorSpinner stroke={"var(--primary-blue--backg-30)"} size={24} strokeW={8}/>
					</div>
					<div className="flexSpace"/>
				</div>
				</div>
			:
			<div className="clients_container">
				{	getStore("searchQryLogisticCustomer")?.length>0 && getStore("clientLogistic_list") && ObjectKeys(getStore("clientLogistic_list"))?.map(cid=>{
					return (
						<ClientItem
							data={getStore("clientLogistic_list")[cid]} 
							elmId={cid} 
							key={cid}
						/>
					)
				})}
			</div>
			}
			</div>
		</div>
	)

}

export default CustomerView;






