import React, { useEffect, useState, useRef } from "react";

import { getStore, updStore, gen16CodeId, getUrlStaticImage } from "../../../stores/Utils";


import { get_print_structure, getById_notary } from "../services/customer_fetch_service";
import { NavLink } from "react-router-dom";


const ClientItem  = ({ data, elmId }) => {
	const [initialize, setInitialize] = useState(false);
	const [obs, set_obs] = useState(0);

	


	useEffect(() => {
		if (!initialize) {
			setInitialize(true);
			
			set_obs(gen16CodeId())
		}
	});


	if(!data?.firstName){
		return null;
	}

	const openUpdView = () => {
		
	}
	

	const getPdfStruct = async () => {
		get_print_structure(openUpdView)
	}

	const update = async () => {
		updStore("marriage_certificate",null);
		updStore("birth_certificate",null);
		updStore("driver_licence_translate",null);
		updStore("data_frm_i598",null);
		
		//getById_notary(data?.customerLogisticId,getPdfStruct)

		// /dashboard-services/customer-detail

	}

	
	let flagImg = data?.countryId==="CUB"?getStore("cuba_flag.png"):getStore("usa_flag.png");


	return (
		<NavLink className=""  to={{
			"pathname": "/logistic-services/customer-detail" ,
			"search": "?cId="+ data?.customerLogisticId + "&view=1"
		}}>
			<div className="client_item_box gWXAaj jlytmu" onClick={update}  style={{marginBottom: 9}}>
				<div className="_dsplFlx">
					<div className="name" >
						{`${data?.firstName}${data?.middleName?" "+data?.middleName:""} ${data?.lastName}`}
					</div>
					<div className="flexSpace"/>
					<div  className="icon blue30 flag" >
						<img src={flagImg} alt={"f;ag"}/>
					</div>
					<div className="name">
						{data?.phoneNumber}
					</div>
				</div>
			</div>
		</NavLink>
	)
}

export default ClientItem;

  