import React, { useEffect, useState, useRef } from "react";



import { getStore, updStore, gen16CodeId, compareJSON, qryStore, fetchEncryptStream } from "../../../stores/Utils";

import { CheckBoxSlide_Cmpt, TextInput_Cmpt, CheckBox_Cmpt, DropDwnPicker_Cmpt } from "../../../components";
import { OpenModal, CloseModal } from "../../../components/DialogHRM";


import DateCalComponent from "./DateCalComponent";



const TextInput = TextInput_Cmpt();




const DropDwnPicker = DropDwnPicker_Cmpt();


const frmNm = "add_logistic_client"

const AddClientInfo  = ({ data, elmId, confirm }) => {
	const [initialize, setInitialize] = useState(false);
	const [obs, set_obs] = useState(0);

	useEffect(() => {
		if (!initialize) {
			setInitialize(true);
			
			set_obs(gen16CodeId())
		}
	});

	const updFrm = (f, v, k) => {
		let frm2 = getStore(frmNm) || {};
		if(k){
			if( !frm2[k]){
				frm2[k] = {};
			}
			frm2[k][f] = v;
		}else{
			frm2[f] = v;
		}
		updStore(frmNm, frm2);
		
		set_obs(gen16CodeId())
	};


	const save  = async ()  => {
		let ffm = getStore(frmNm);

		if(ffm && ffm["dateOfBirth"]){
			let nd = (new Date(ffm["dateOfBirth"])).getTime();
			if(nd){
				ffm["dob"] = nd;
			}
		}
		ffm["customerLogisticId"] = gen16CodeId();


		
		let bdyq2 = {...getStore(qryStore())?.add_customer_logistic};
		bdyq2.params = {
			businessId:  getStore("profileUser")?.businessId,
		}
		bdyq2.form = ffm;	
		
		const res = fetchEncryptStream(bdyq2);
		const td = await res;
		if (td && !td.error) {
			close();
			confirm && confirm();
		}
		///let pdfUri = await generateTranslateAddClient(ffm, true, true);
		///window.open(pdfUri);
	};


	const close  = ()  => {
		data?.modalID && CloseModal({id:data?.modalID});
	}

	
	const handlePick = (v,f)=>{
		updFrm(f,v.clientNotaryId)
	}

	

	return (
		<div style={{
			maxHeight: "80vh",
			width: "960px",
			overflow: "auto",
			background: "var(--dark-800)",
			borderRadius: 13,
			padding: "10px 19px"
		}}>
			<div className="_dsplFlx ">
				<p className="form_title ">
					Agregar Cliente
				</p>
				<div className="flexSpace"/>
				
			</div>

			
			
			<div className="_dsplFlx spaceAround flxWrp " style={{marginTop: 30}}>
			
				
				<TextInput  
					init={getStore(frmNm)?.["firstName"]} 
					label={"Nombre"} 
					width={200} 
					updChanges={(e)=>updFrm("firstName",e)}
				/>
				<TextInput  
					init={getStore(frmNm)?.["middleName"]} 
					label={"Segundo Nombre"} 
					width={200} 
					updChanges={(e)=>updFrm("middleName",e)}
				/>
				<TextInput  
					init={getStore(frmNm)?.["lastName"]} 
					label={"Apellidos"} 
					width={360} 
					updChanges={(e)=>updFrm("lastName",e)}
				/>
				
			</div>


		
			<div className="_dsplFlx spaceAround flxWrp " style={{marginTop: 10}}>
				
				<TextInput  
					init={getStore(frmNm)?.["phoneNumber"]} 
					label={"Telefono"} 
					width={160} 
					updChanges={(e)=>updFrm("phoneNumber",e)}
				/>

				<TextInput  
					init={getStore(frmNm)?.["phoneNumberAlternative"]} 
					label={"Telefono Alternativo"} 
					width={160} 
					updChanges={(e)=>updFrm("phoneNumberAlternative",e)}
				/>
				
				
			</div>

			<div className="_dsplFlx spaceAround flxWrp " style={{marginTop: 10}}>
				
				<TextInput  
					init={getStore(frmNm)?.["cid"]} 
					label={"Licencia o Id"} 
					width={190} 
					updChanges={(e)=>updFrm("cid",e)}
				/>

				<TextInput  
					init={getStore(frmNm)?.["email"]} 
					label={"Email"} 
					width={420} 
					updChanges={(e)=>updFrm("email",e)}
				/>
				
				
			</div>



			
			<div className="separator"/>


			

			<p className="group_title">
				Direccion Actual 
			</p>
			<div className="_dsplFlx spaceAround flxWrp"> 
				
				
				
			</div>
			<div className="_dsplFlx spaceAround flxWrp" style={{marginTop: 20}}> 
				<div className="flexSpace"/>
				<div style={{marginTop:19}}>
					<DropDwnPicker 
						init={getStore(frmNm)?.["currentLocation"]?.["country"]}
						lbl_empty={"Pais"} 
						list={
							[
								{label: "United States", id:"USA"},
								{label: "Cuba", id:"CUB"},
							]
						}
						onSelect={(e)=>updFrm("country",e, "currentLocation")} 
						background={"var(--dark-900)"}
						color={"var(--light-200)"}
					/>
				</div>	
				<div className="flexSpace"/>
				<TextInput  
					init={getStore(frmNm)?.["currentLocation"]?.["address"]} 
					label={"Calle"} 
					width={600} 
					updChanges={(e)=>updFrm("address",e, "currentLocation")}
				/>
				<div className="flexSpace"/>
			</div>
			<div className="_dsplFlx spaceAround flxWrp" style={{marginTop: 20}}> 
				
				<TextInput  
					init={getStore(frmNm)?.["currentLocation"]?.["city"]} 
					label={"Ciudad"} 
					width={200} 
					updChanges={(e)=>updFrm("city",e, "currentLocation")}
				/>
				<TextInput  
					init={getStore(frmNm)?.["currentLocation"]?.["state"]} 
					label={"Estado"} 
					width={200} 
					updChanges={(e)=>updFrm("state",e, "currentLocation")}
				/>
				
				<TextInput  
					init={getStore(frmNm)?.["currentLocation"]?.["zipcode"]} 
					label={"Codigo Postal"} 
					width={120} 
					updChanges={(e)=>updFrm("zipcode",e, "currentLocation")}
				/>
			</div>

		


			<div className="_dsplFlx ">
				<div className="flexSpace"/>
				<div className="card">
					<GrayButton label={"Agregar"} clickHandler={save}/>
				</div>
			</div>
		</div>
	);
};

export default AddClientInfo;




const GrayButton  = ({ clickHandler, label }) => {
	return (
		<div className=" jaqJnq_hrm1"  >
			<button className="gHAsFI_hrm1 dqnOfN jUrKkb" onClick={clickHandler}>
				<span className=" jaqJnq_hrm1" >
					{label}
				</span>
			</button>
		</div>
	)
}